    fn tokenToSymbol(self: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 52,
            .@"indent" => 56,
            .@"outdent" => 57,
            .@"string_dq" => 65,
            .@"integer" => 112,
            .@"real" => 113,
            .@"string_sq" => 114,
            .@"true" => 115,
            .@"false" => 116,
            .@"assign" => 63,
            .@"colon" => 69,
            .@"comma" => 70,
            .@"not_sym" => 74,
            .@"question" => 75,
            .@"star" => 76,
            .@"lbracket" => 77,
            .@"rbracket" => 78,
            .@"bar" => 81,
            .@"minus" => 103,
            .@"dot" => 105,
            .@"lparen" => 108,
            .@"rparen" => 109,
            .@"at" => 119,
            .@"lbrace" => 120,
            .@"rbrace" => 123,
            .@"lt" => 142,
            .@"gt" => 143,
            .@"plus" => 147,
            .@"slash" => 148,
            .@"percent" => 149,
            .@"arrow" => 73,
            .@"fat_arrow" => 88,
            .@"nullish" => 89,
            .@"plus_assign" => 98,
            .@"minus_assign" => 99,
            .@"star_assign" => 100,
            .@"slash_assign" => 101,
            .@"const_assign" => 102,
            .@"pipe" => 137,
            .@"or_sym" => 138,
            .@"and_sym" => 139,
            .@"eq" => 140,
            .@"ne" => 141,
            .@"le" => 144,
            .@"ge" => 145,
            .@"dotdot" => 146,
            .@"power" => 150,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *Parser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return SYM_IDENT;
        if (self.try_ident_as_keyword(token, text)) |sym| return sym;
        return SYM_IDENT;
    }

    fn try_ident_as_keyword(self: *Parser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.state_stack.getLast();
        if (rip.keyword_as(text)) |id| {
            const id_idx = @intFromEnum(id);
            const sym = keyword_to_symbol[id_idx];
            if (sym != 0 and getAction(state, sym) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return sym;
            }
            const fallback = keyword_fallback_symbol;
            if (fallback != 0 and getAction(state, fallback) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *Parser) !Sexp {
        self.injected_token = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseExpr(self: *Parser) !Sexp {
        self.injected_token = SYM_expr_START;
        return self.doParse(SYM_expr);
    }
};

// Symbol IDs
const SYM_program: u16 = 3;
const SYM_program_START: u16 = 125;
const SYM_expr: u16 = 4;
const SYM_expr_START: u16 = 127;
const SYM_IDENT: u16 = 59;

// Mapping from rip.keyword_id to grammar symbol IDs (computed at comptime)
const keyword_to_symbol = blk: {
    var arr: [512]u16 = .{0} ** 512;
    if (@hasField(rip.keyword_id, "NEWLINE")) arr[@intFromEnum(rip.keyword_id.NEWLINE)] = 52;
    if (@hasField(rip.keyword_id, "PUB")) arr[@intFromEnum(rip.keyword_id.PUB)] = 53;
    if (@hasField(rip.keyword_id, "EXTERN")) arr[@intFromEnum(rip.keyword_id.EXTERN)] = 54;
    if (@hasField(rip.keyword_id, "EXPORT")) arr[@intFromEnum(rip.keyword_id.EXPORT)] = 55;
    if (@hasField(rip.keyword_id, "INDENT")) arr[@intFromEnum(rip.keyword_id.INDENT)] = 56;
    if (@hasField(rip.keyword_id, "OUTDENT")) arr[@intFromEnum(rip.keyword_id.OUTDENT)] = 57;
    if (@hasField(rip.keyword_id, "FUN")) arr[@intFromEnum(rip.keyword_id.FUN)] = 58;
    if (@hasField(rip.keyword_id, "IDENT")) arr[@intFromEnum(rip.keyword_id.IDENT)] = 59;
    if (@hasField(rip.keyword_id, "SUB")) arr[@intFromEnum(rip.keyword_id.SUB)] = 60;
    if (@hasField(rip.keyword_id, "USE")) arr[@intFromEnum(rip.keyword_id.USE)] = 61;
    if (@hasField(rip.keyword_id, "ALIAS")) arr[@intFromEnum(rip.keyword_id.ALIAS)] = 62;
    if (@hasField(rip.keyword_id, "TEST")) arr[@intFromEnum(rip.keyword_id.TEST)] = 64;
